const params = $('Set Global Parameters').first().json;
const deck   = $input.first().json.data;

// Parse animation types (comma-separated, trims whitespace)
const animTypes = params.AnimationTypes.split(',').map(s => s.trim()).filter(Boolean);

// Read optional model and sampler config from Deck.json.
// All fields have safe defaults so the flow works even if the deck author
// only fills in the required Prompts / Assets / Geometries sections.
const models  = deck.Models   || {};
const samplers = deck.Samplers || {};
const kfSamp  = samplers.Keyframe || {};

const jobs = [];

for (const animType of animTypes) {
  const animPrompts = deck.Prompts?.[animType];
  if (!animPrompts) {
    console.warn(`[Build Keyframe Job List] Deck.json is missing Prompts.${animType} — skipping.`);
    continue;
  }

  const keyframes = animPrompts.Keyframes;
  if (!Array.isArray(keyframes) || keyframes.length === 0) {
    console.warn(`[Build Keyframe Job List] Prompts.${animType}.Keyframes is empty — skipping.`);
    continue;
  }

  keyframes.forEach((prompt, idx) => {
    jobs.push({
      // Identity
      Phase:         'keyframe',
      AnimationType: animType,
      KeyframeIndex: idx,
      KeyframeCount: keyframes.length,

      // Prompts  (art-team owned — edit in Deck.json)
      PositivePrompt: prompt,
      NegativePrompt: animPrompts.Negative || '',

      // Output locations (from Deck.json)
      OutputPrefix: `KF_${animType}_${idx}`,
      KeyframeDir:  deck.Assets.AnimationKeyframes,
      OutputDir:    deck.Assets.Directory,
      FinalOutput:  deck.Assets[animType],

      // Geometry (from Deck.json)
      Width:        deck.Geometries.Animation.Width,
      Height:       deck.Geometries.Animation.Height,
      FPS:          deck.Geometries.Animation.FrameRate,
      InterpFrames: deck.Geometries.Animation.InterpolationFrames,

      // Keyframe model + sampler  (Deck.json -> Models / Samplers.Keyframe)
      // To swap the model, add Models.KeyframeCheckpoint to your Deck.json.
      Checkpoint: models.KeyframeCheckpoint || 'dreamshaper_8.safetensors',
      Steps:      kfSamp.Steps    ?? 20,
      CFG:        kfSamp.CFG      ?? 7.0,
      Sampler:    kfSamp.Sampler  || 'dpmpp_2m',
      Scheduler:  kfSamp.Scheduler || 'karras',
      Denoise:    kfSamp.Denoise  ?? 1.0
    });
  });
}

if (jobs.length === 0) {
  throw new Error(
    '[Build Keyframe Job List] No jobs created. ' +
    'Check that AnimationTypes matches keys in Deck.json Prompts, ' +
    'and that each Prompts.<Type>.Keyframes array is non-empty.'
  );
}

return jobs.map(j => ({ json: j }));

// Receives all completed keyframe results from Loop Keyframes (output 1).
// Groups by AnimationType, sorts by KeyframeIndex, creates adjacent-pair
// jobs for the image-to-video interpolation step.
const allItems = $input.all();

// Read interpolation model + sampler config directly from the parsed deck.
// Keeping this here (not in keyframe nodes) maintains clean separation of concerns.
const deck    = $('Parse Deck.json').first().json.data;
const models  = deck.Models   || {};
const samplers = deck.Samplers || {};
const ipSamp  = samplers.Interpolation || {};

const byType = {};
for (const item of allItems) {
  const d = item.json;
  if (!byType[d.AnimationType]) byType[d.AnimationType] = [];
  byType[d.AnimationType].push(d);
}

const interpJobs = [];

for (const [animType, frames] of Object.entries(byType)) {
  frames.sort((a, b) => a.KeyframeIndex - b.KeyframeIndex);

  if (frames.length < 2) {
    console.warn(
      `[Build Interpolation Job List] ${animType} has only ${frames.length} ` +
      `keyframe(s) — need >= 2 to interpolate. Skipping.`
    );
    continue;
  }

  for (let i = 0; i < frames.length - 1; i++) {
    const frameA = frames[i];
    const frameB = frames[i + 1];

    interpJobs.push({
      // Identity
      Phase:         'interpolate',
      AnimationType: animType,
      PairIndex:     i,

      // Source frames
      FrameAPath:     frameA.SavedPath,
      FrameBPath:     frameB.SavedPath,
      FrameAFilename: frameA.SavedFilename,
      FrameBFilename: frameB.SavedFilename,

      // Prompts & output
      PositivePrompt: frameA.PositivePrompt,
      NegativePrompt: frameA.NegativePrompt,
      OutputPrefix:   `INTERP_${animType}_${i}_${i + 1}`,
      OutputDir:      frameA.OutputDir,
      KeyframeDir:    frameA.KeyframeDir,
      FinalOutput:    frameA.FinalOutput,

      // Geometry
      Width:        frameA.Width,
      Height:       frameA.Height,
      FPS:          frameA.FPS,
      InterpFrames: frameA.InterpFrames,

      // Interp model + sampler  (Deck.json -> Models / Samplers.Interpolation)
      // To swap models, add Models.InterpolationUNet / CLIPName / VAEName to Deck.json.
      UNetName:        models.InterpolationUNet      || 'wan2.2_i2v_high_noise_14B_fp8_scaled.safetensors',
      CLIPName:        models.InterpolationCLIP      || 'umt5_xxl_fp8_e4m3fn_scaled.safetensors',
      VAEName:         models.InterpolationVAE       || 'wan_2.1_vae.safetensors',
      InterpSteps:     ipSamp.Steps      ?? 20,
      InterpCFG:       ipSamp.CFG        ?? 7.0,
      InterpSampler:   ipSamp.Sampler    || 'uni_pc_bh2',
      InterpScheduler: ipSamp.Scheduler  || 'sgm_uniform',
      InterpDenoise:   ipSamp.Denoise    ?? 1.0,
      InterpShift:     ipSamp.Shift      ?? 3.0
    });
  }
}

if (interpJobs.length === 0) {
  throw new Error(
    '[Build Interpolation Job List] No interpolation jobs created. ' +
    'Each animation type needs at least 2 entries in Deck.json Prompts.<Type>.Keyframes.'
  );
}

return interpJobs.map(j => ({ json: j }));

// Group all clips by AnimationType and build FFmpeg concat commands.
const allItems = $input.all();

const byType = {};
for (const item of allItems) {
  const d = item.json;
  if (!byType[d.AnimationType]) byType[d.AnimationType] = [];
  byType[d.AnimationType].push(d);
}

const concatJobs = [];
for (const [animType, clips] of Object.entries(byType)) {
  clips.sort((a, b) => a.PairIndex - b.PairIndex);

  // Build a temporary concat list file path
  const concatListPath = `${clips[0].KeyframeDir}\\${animType}_concat.txt`;
  const clipPaths = clips.map(c => c.ClipPath.replace(/\//g, '\\'));
  const finalOutput = clips[0].FinalOutput.replace(/\//g, '\\');

  // Write concat list content (one line per clip)
  const concatContent = clipPaths.map(p => `file '${p}'`).join('\n');

  concatJobs.push({
    AnimationType: animType,
    ConcatListPath: concatListPath,
    ConcatContent: concatContent,
    FinalOutput: finalOutput,
    ClipPaths: clipPaths
  });
}

return concatJobs.map(j => ({ json: j }));

const fs            = require('fs');
const path          = require('path');
const { execSync }  = require('child_process');
const allJobs       = $input.all().map(function(item) { return item.json; });
const results       = [];

for (const job of allJobs) {
  // Ensure output directory exists
  const outDir = path.dirname(job.FinalOutput);
  fs.mkdirSync(outDir, { recursive: true });

  // Ensure concat-list directory exists and write the list file
  const listDir = path.dirname(job.ConcatListPath);
  fs.mkdirSync(listDir, { recursive: true });
  fs.writeFileSync(job.ConcatListPath, job.ConcatContent, 'utf8');

  // Run ffmpeg
  const cmd = `ffmpeg -y -f concat -safe 0 -i "${job.ConcatListPath}" -c copy "${job.FinalOutput}"`;
  let stdout = '', stderr = '';
  try {
    stdout = execSync(cmd, { encoding: 'utf8', stdio: ['pipe','pipe','pipe'] });
  } catch (e) {
    stderr = e.stderr || e.message || String(e);
    throw new Error('[FFmpeg Concat Clips] ffmpeg failed for ' + job.AnimationType + ':\n' + stderr);
  }

  results.push({
    AnimationType: job.AnimationType,
    FinalOutput:   job.FinalOutput,
    Status:        'done'
  });
}

if (results.length === 0) throw new Error('[FFmpeg Concat Clips] No concat jobs were processed');
return results.map(function(r) { return { json: r }; });

const results = $input.all().map(item => ({
  AnimationType: item.json.AnimationType,
  FinalOutput: item.json.FinalOutput,
  Status: 'Complete'
}));
console.log('Stop-motion generation complete:', JSON.stringify(results, null, 2));
return results.map(r => ({ json: r }));

