const axios = require('axios');
const fs   = require('fs');
const path = require('path');
const params         = $('Set Global Parameters').first().json;
const comfyUIAPI     = params.ComfyUIAPI;
const comfyOutputDir = params.ComfyUIOutputDir;
const allJobs        = $input.all().map(function(item) { return item.json; });
const sleep = function(ms) { return new Promise(function(r) { setTimeout(r, ms); }); };
const results = [];

for (const job of allJobs) {
  // --- Insertable keyframe check ---
  // If KF_<AnimType>_<Index>.png exists in the deck's keyframe dir, use it directly
  // instead of generating. Drop it there to override any keyframe with a hand-crafted image.
  const insertableSrc = path.join(job.KeyframeDir, job.OutputPrefix + '.png');
  if (fs.existsSync(insertableSrc)) {
    const destFilename = job.OutputPrefix + '_manual.png';
    fs.copyFileSync(insertableSrc, path.join(comfyOutputDir, destFilename));
    console.warn('[Generate All Keyframes] Using insertable keyframe for ' + job.OutputPrefix);
    results.push(Object.assign({}, job, {
      PromptId: 'manual',
      SavedFilename: destFilename,
      SavedPath: comfyOutputDir + '/' + destFilename
    }));
    continue;
  }

  const comfyPrompt = {
    "1": { "class_type": "CheckpointLoaderSimple", "inputs": { "ckpt_name": job.Checkpoint } },
    "2": { "class_type": "CLIPTextEncode", "inputs": { "text": job.PositivePrompt, "clip": ["1", 1] } },
    "3": { "class_type": "CLIPTextEncode", "inputs": { "text": job.NegativePrompt, "clip": ["1", 1] } },
    "4": { "class_type": "EmptyLatentImage", "inputs": { "width": job.Width, "height": job.Height, "batch_size": 1 } },
    "5": { "class_type": "KSampler", "inputs": {
        "seed": Math.floor(Math.random() * 999999999),
        "steps": job.Steps, "cfg": job.CFG,
        "sampler_name": job.Sampler, "scheduler": job.Scheduler, "denoise": job.Denoise,
        "model": ["1",0], "positive": ["2",0], "negative": ["3",0], "latent_image": ["4",0]
      }
    },
    "6": { "class_type": "VAEDecode", "inputs": { "samples": ["5", 0], "vae": ["1", 2] } },
    "7": { "class_type": "SaveImage", "inputs": { "images": ["6", 0], "filename_prefix": job.OutputPrefix } }
  };

  const submitRes = await axios.post(comfyUIAPI + '/prompt', { prompt: comfyPrompt });
  const promptId = submitRes.data.prompt_id;

  let done = false;
  for (let attempt = 0; attempt < 60 && !done; attempt++) {
    await sleep(3000);
    const historyRes = await axios.get(comfyUIAPI + '/history/' + promptId);
    const entry = historyRes.data[promptId];
    if (entry && entry.outputs && entry.outputs['7'] &&
        entry.outputs['7'].images && entry.outputs['7'].images.length > 0) {
      const filename = entry.outputs['7'].images[0].filename;
      results.push(Object.assign({}, job, {
        PromptId: promptId,
        SavedFilename: filename,
        SavedPath: comfyOutputDir + '/' + filename
      }));
      done = true;
    }
  }
  if (!done) throw new Error('[Generate All Keyframes] Timeout: ' + job.OutputPrefix + ' did not finish within 3 min');
}

if (results.length === 0) throw new Error('[Generate All Keyframes] No keyframes generated successfully');
return results.map(function(r) { return { json: r }; });

const axios = require('axios');
const fs   = require('fs');
const path = require('path');
const params         = $('Set Global Parameters').first().json;
const comfyUIAPI     = params.ComfyUIAPI;
const comfyOutputDir = params.ComfyUIOutputDir;
const comfyInputDir  = params.ComfyUIInputDir;
const allJobs        = $input.all().map(function(item) { return item.json; });
const sleep = function(ms) { return new Promise(function(r) { setTimeout(r, ms); }); };
const results = [];

for (const job of allJobs) {
  fs.copyFileSync(path.join(comfyOutputDir, job.FrameAFilename), path.join(comfyInputDir, job.FrameAFilename));
  fs.copyFileSync(path.join(comfyOutputDir, job.FrameBFilename), path.join(comfyInputDir, job.FrameBFilename));

  const comfyPrompt = {
    "1":  { "class_type": "UNETLoader",     "inputs": { "unet_name": job.UNetName, "weight_dtype": "default" } },
    "2":  { "class_type": "CLIPLoader",     "inputs": { "clip_name": job.CLIPName, "type": "wan" } },
    "3":  { "class_type": "VAELoader",      "inputs": { "vae_name": job.VAEName } },
    "4":  { "class_type": "CLIPTextEncode", "inputs": { "text": job.PositivePrompt, "clip": ["2",0] } },
    "5":  { "class_type": "CLIPTextEncode", "inputs": { "text": job.NegativePrompt, "clip": ["2",0] } },
    "6":  { "class_type": "LoadImage",      "inputs": { "image": job.FrameAFilename, "upload": "image" } },
    "13": { "class_type": "LoadImage",      "inputs": { "image": job.FrameBFilename, "upload": "image" } },
    "7":  { "class_type": "WanFirstLastFrameToVideo","inputs": {
        "width": job.Width, "height": job.Height, "length": job.InterpFrames, "batch_size": 1,
        "positive": ["4",0], "negative": ["5",0], "vae": ["3",0],
        "start_image": ["6",0], "end_image": ["13",0]
      }
    },
    "9":  { "class_type": "ModelSamplingSD3","inputs": { "shift": job.InterpShift, "model": ["1",0] } },
    "10": { "class_type": "KSampler","inputs": {
        "seed": Math.floor(Math.random() * 999999999),
        "steps": job.InterpSteps, "cfg": job.InterpCFG,
        "sampler_name": job.InterpSampler, "scheduler": job.InterpScheduler, "denoise": job.InterpDenoise,
        "model": ["9",0], "positive": ["7",0], "negative": ["7",1], "latent_image": ["7",2]
      }
    },
    "11": { "class_type": "VAEDecode",        "inputs": { "samples": ["10",0], "vae": ["3",0] } },
    "12": { "class_type": "VHS_VideoCombine", "inputs": {
        "frame_rate": job.FPS, "loop_count": 0, "filename_prefix": job.OutputPrefix,
        "format": "video/h264-mp4", "pix_fmt": "yuv420p", "crf": 19,
        "save_metadata": true, "trim_to_audio": false, "pingpong": false, "save_output": true,
        "images": ["11",0]
      }
    }
  };

  const submitRes = await axios.post(comfyUIAPI + '/prompt', { prompt: comfyPrompt });
  const promptId = submitRes.data.prompt_id;

  let done = false;
  for (let attempt = 0; attempt < 600 && !done; attempt++) {
    await sleep(3000);
    const historyRes = await axios.get(comfyUIAPI + '/history/' + promptId);
    const entry = historyRes.data[promptId];
    if (entry && entry.outputs && entry.outputs['12'] &&
        entry.outputs['12'].gifs && entry.outputs['12'].gifs.length > 0) {
      const filename = entry.outputs['12'].gifs[0].filename;
      results.push(Object.assign({}, job, {
        InterpPromptId: promptId,
        ClipFilename: filename,
        ClipPath: comfyOutputDir + '/' + filename
      }));
      done = true;
    }
  }
  if (!done) throw new Error('[Generate All Interpolations] Timeout: ' + job.OutputPrefix + ' did not finish within 30 min');
}

if (results.length === 0) throw new Error('[Generate All Interpolations] No interpolation clips generated successfully');
return results.map(function(r) { return { json: r }; });
